(
  'Small Bathroom Refresh',
  'Transform a tired bathroom in a weekend without a contractor. Paint the vanity, swap hardware, and upgrade fixtures for a magazine look on a beer budget.',
  'renovation',
  'https://images.unsplash.com/photo-1552321554-5fefe8c9ef14?w=800&h=1000&fit=crop',
  true, true, true, 423, 4.7, 'beginner',
  ARRAY['bathroom','weekend','budget','paint']::text[], 950.00, 16.0,
  '{"stages":[{"title":"Prep & Clear","description":"Empty and protect the space.","reason":"Paint needs clean surfaces.","estimated_cost":25,"estimated_hours":2,"steps":[{"title":"Clear vanity and shelves","description":"Remove toiletries, trash, decor.","skill_level":"beginner","estimated_minutes":30,"tools_needed":[],"materials_needed":[{"name":"Trash bags","quantity":2,"unit":"bags"}]},{"title":"Tape and drop-cloth","description":"Cover floor and tape trim, mirror, toilet.","skill_level":"beginner","estimated_minutes":30,"tools_needed":["painters tape","utility knife"],"materials_needed":[{"name":"Drop cloth","quantity":1,"unit":"piece"}]},{"title":"Clean with TSP","description":"Degreaser on walls and vanity so paint sticks.","skill_level":"beginner","estimated_minutes":45,"tools_needed":["sponge"],"materials_needed":[{"name":"TSP","quantity":1,"unit":"bottle"}]}]},{"title":"Paint Vanity & Walls","description":"Two coats of cabinet paint transforms everything.","reason":"Paint before new hardware so drips are hidden.","estimated_cost":150,"estimated_hours":8,"steps":[{"title":"Prime vanity","description":"Zinsser BIN stain-blocking primer.","skill_level":"beginner","estimated_minutes":60,"tools_needed":["foam roller"],"materials_needed":[{"name":"BIN primer","quantity":1,"unit":"quart"}]},{"title":"Paint two coats","description":"Thin even coats, 4hr between.","skill_level":"intermediate","estimated_minutes":180,"tools_needed":["foam roller"],"materials_needed":[{"name":"Cabinet paint","quantity":1,"unit":"quart"}]},{"title":"Paint walls","description":"Semi-gloss for moisture. Two coats.","skill_level":"beginner","estimated_minutes":180,"tools_needed":["roller"],"materials_needed":[{"name":"Bathroom paint","quantity":1,"unit":"gallon"}]}]},{"title":"Hardware Swap","description":"New knobs, faucet, mirror.","reason":"Visual wins come last.","estimated_cost":500,"estimated_hours":6,"steps":[{"title":"Install cabinet hardware","description":"Measure twice, drill once.","skill_level":"beginner","estimated_minutes":45,"tools_needed":["drill"],"materials_needed":[{"name":"Knobs","quantity":6,"unit":"pieces"}]},{"title":"Replace faucet","description":"Shut water first. Disconnect supply lines.","skill_level":"intermediate","estimated_minutes":90,"tools_needed":["basin wrench"],"materials_needed":[{"name":"Faucet","quantity":1,"unit":"unit"}]},{"title":"Hang mirror and light","description":"Kill breaker first if swapping light.","skill_level":"intermediate","estimated_minutes":75,"tools_needed":["drill","voltage tester"],"materials_needed":[{"name":"Mirror","quantity":1,"unit":"unit"}]}]}]}'::jsonb
