(
  'Modern Kitchen Backsplash',
  'Subway tile is the cheapest cosmetic kitchen upgrade. Walks you through prep, tile install, and grout.',
  'renovation',
  'https://images.unsplash.com/photo-1556909114-f6e7ad7d3136?w=800&h=600&fit=crop',
  true, true, false, 287, 4.5, 'intermediate',
  ARRAY['kitchen','tile','backsplash']::text[], 425.00, 14.0,
  '{"stages":[{"title":"Prep the Wall","description":"Tile only sticks to clean flat primed drywall.","reason":"Bad prep is the #1 cause of failing tile jobs.","estimated_cost":40,"estimated_hours":3,"steps":[{"title":"Kill power, remove outlet covers","description":"Test with voltage tester before touching.","skill_level":"beginner","estimated_minutes":15,"tools_needed":["voltage tester"],"materials_needed":[]},{"title":"Clean wall with degreaser","description":"TSP or Krud Kutter. Grease ruins adhesion.","skill_level":"beginner","estimated_minutes":30,"tools_needed":["sponge"],"materials_needed":[{"name":"Degreaser","quantity":1,"unit":"bottle"}]},{"title":"Fill holes and sand","description":"Bumps telegraph through tile.","skill_level":"beginner","estimated_minutes":45,"tools_needed":["putty knife"],"materials_needed":[{"name":"Spackle","quantity":1,"unit":"tub"}]},{"title":"Prime","description":"Bonding primer for wet areas.","skill_level":"beginner","estimated_minutes":60,"tools_needed":["roller"],"materials_needed":[{"name":"Bonding primer","quantity":1,"unit":"quart"}]}]},{"title":"Set Tile","description":"Layout, butter, and set.","reason":"Start from focal wall so cuts land in corners.","estimated_cost":280,"estimated_hours":7,"steps":[{"title":"Snap level line","description":"Measure up one tile plus grout line.","skill_level":"beginner","estimated_minutes":20,"tools_needed":["level","chalk line"],"materials_needed":[]},{"title":"Spread thinset","description":"Work 3ft sections so it doesnt skin over.","skill_level":"intermediate","estimated_minutes":30,"tools_needed":["notched trowel"],"materials_needed":[{"name":"Tile mastic","quantity":1,"unit":"gallon"}]},{"title":"Set tiles with spacers","description":"Press firm with slight wiggle.","skill_level":"intermediate","estimated_minutes":180,"tools_needed":["spacers"],"materials_needed":[{"name":"Subway tile","quantity":40,"unit":"sqft"}]},{"title":"Cut edge tiles","description":"Score and snap with a manual cutter.","skill_level":"intermediate","estimated_minutes":90,"tools_needed":["tile cutter"],"materials_needed":[]}]},{"title":"Grout & Seal","description":"Float, wipe, buff, seal.","reason":"Tiles must be set before applying force.","estimated_cost":105,"estimated_hours":4,"steps":[{"title":"Mix grout","description":"Peanut butter consistency. Small batches.","skill_level":"beginner","estimated_minutes":15,"tools_needed":["bucket","drill paddle"],"materials_needed":[{"name":"Unsanded grout","quantity":1,"unit":"bag"}]},{"title":"Float grout","description":"45deg angle, push diagonally across tile.","skill_level":"intermediate","estimated_minutes":45,"tools_needed":["rubber float"],"materials_needed":[]},{"title":"Wipe with sponge","description":"Rinse often. Circles.","skill_level":"beginner","estimated_minutes":60,"tools_needed":["sponge"],"materials_needed":[]},{"title":"Caulk corners and seal","description":"Silicone at countertop. Grout sealer after 72hrs.","skill_level":"beginner","estimated_minutes":45,"tools_needed":["caulk gun"],"materials_needed":[{"name":"Silicone caulk","quantity":1,"unit":"tube"}]}]}]}'::jsonb
),
(
  'Simple Shaker Cabinet',
  'A versatile shaker cabinet for nightstand, vanity base, or living room storage. Plywood and poplar with classic frame and panel doors.',
  'furniture',
  'https://images.unsplash.com/photo-1606041008023-472dfb5e530f?w=800&h=1200&fit=crop',
  true, true, false, 156, 4.6, 'intermediate',
  ARRAY['cabinet','woodworking','shaker']::text[], 210.00, 18.0,
  '{"stages":[{"title":"Cut Lumber","description":"Break down plywood and mill poplar to size.","reason":"Cutting first keeps shop clean for assembly.","estimated_cost":120,"estimated_hours":4,"steps":[{"title":"Cut plywood panels","description":"Circular saw with straightedge or track saw.","skill_level":"intermediate","estimated_minutes":90,"tools_needed":["circular saw","straightedge"],"materials_needed":[{"name":"3/4 birch plywood","quantity":1,"unit":"sheet"}]},{"title":"Rip door stiles and rails","description":"2 inch wide for classic shaker.","skill_level":"intermediate","estimated_minutes":60,"tools_needed":["table saw"],"materials_needed":[{"name":"Poplar boards","quantity":3,"unit":"boards"}]},{"title":"Sand to 220 grit","description":"Before assembly — easier than inside corners.","skill_level":"beginner","estimated_minutes":60,"tools_needed":["orbital sander"],"materials_needed":[]}]},{"title":"Build Box","description":"Assemble carcass with pocket screws and glue.","reason":"Box first, then doors fit the opening.","estimated_cost":30,"estimated_hours":3,"steps":[{"title":"Drill pocket holes","description":"Kreg jig at 3/4 inch setting.","skill_level":"beginner","estimated_minutes":45,"tools_needed":["Kreg jig","drill"],"materials_needed":[{"name":"Pocket screws","quantity":1,"unit":"box"}]},{"title":"Glue and screw sides","description":"Clamp square while driving screws.","skill_level":"intermediate","estimated_minutes":45,"tools_needed":["clamps","drill"],"materials_needed":[{"name":"Wood glue","quantity":1,"unit":"bottle"}]},{"title":"Attach back panel","description":"1/4 plywood in rabbet or on back edges.","skill_level":"intermediate","estimated_minutes":30,"tools_needed":["brad nailer"],"materials_needed":[{"name":"Brad nails","quantity":1,"unit":"pack"}]}]},{"title":"Doors","description":"Frame and panel doors with hidden hinges.","reason":"Doors last so you can fit to actual opening.","estimated_cost":40,"estimated_hours":6,"steps":[{"title":"Cut grooves for panels","description":"1/4 groove 1/2 deep inside edge.","skill_level":"advanced","estimated_minutes":60,"tools_needed":["router","slot cutter"],"materials_needed":[]},{"title":"Cut tenons on rails","description":"Match groove size.","skill_level":"advanced","estimated_minutes":45,"tools_needed":["table saw"],"materials_needed":[]},{"title":"Glue up doors","description":"Glue frame joints only, never the panel.","skill_level":"intermediate","estimated_minutes":30,"tools_needed":["clamps"],"materials_needed":[]},{"title":"Install hinges","description":"35mm cups with forstner bit.","skill_level":"intermediate","estimated_minutes":60,"tools_needed":["forstner bit","drill"],"materials_needed":[{"name":"Euro hinges","quantity":2,"unit":"pairs"}]}]},{"title":"Finish","description":"Prime, paint, hardware.","reason":"Finish after fit, before install.","estimated_cost":20,"estimated_hours":5,"steps":[{"title":"Fill holes and caulk","description":"Paintable filler and latex caulk.","skill_level":"beginner","estimated_minutes":30,"tools_needed":["putty knife"],"materials_needed":[{"name":"Wood filler","quantity":1,"unit":"tub"}]},{"title":"Prime","description":"BIN shellac primer — fast, sands easy.","skill_level":"beginner","estimated_minutes":60,"tools_needed":["foam roller"],"materials_needed":[{"name":"Shellac primer","quantity":1,"unit":"quart"}]},{"title":"Paint two coats","description":"Sand 320 between coats.","skill_level":"intermediate","estimated_minutes":120,"tools_needed":["foam roller"],"materials_needed":[{"name":"Cabinet paint","quantity":1,"unit":"quart"}]}]}]}'::jsonb
),
(
  'Floating Wall Shelves',
  'Hidden bracket floating shelves from solid wood. No visible hardware, holds serious weight, looks expensive.',
  'furniture',
  'https://images.unsplash.com/photo-1555041469-a586c61ea9bc?w=800&h=600&fit=crop',
  true, true, false, 612, 4.8, 'beginner',
  ARRAY['shelves','wall','decor','weekend']::text[], 100.00, 5.0,
  '{"stages":[{"title":"Cut & Finish Wood","description":"Pine or oak cut and stained.","reason":"Finish before install to avoid wall drips.","estimated_cost":60,"estimated_hours":2,"steps":[{"title":"Pick your wood","description":"2x8 or 2x10 solid wood, pine for paint or oak for stain.","skill_level":"beginner","estimated_minutes":30,"tools_needed":[],"materials_needed":[{"name":"Solid wood plank","quantity":3,"unit":"boards"}]},{"title":"Cut to length","description":"Miter saw or circular saw.","skill_level":"beginner","estimated_minutes":20,"tools_needed":["miter saw"],"materials_needed":[]},{"title":"Sand smooth","description":"80 to 220 grit.","skill_level":"beginner","estimated_minutes":30,"tools_needed":["orbital sander"],"materials_needed":[]},{"title":"Stain and seal","description":"Two thin coats, wipe excess, poly topcoat.","skill_level":"beginner","estimated_minutes":45,"tools_needed":["foam brush"],"materials_needed":[{"name":"Stain","quantity":1,"unit":"can"},{"name":"Polyurethane","quantity":1,"unit":"can"}]}]},{"title":"Install Brackets","description":"Steel rod brackets into studs.","reason":"Must hit studs — drywall anchors will fail.","estimated_cost":30,"estimated_hours":1,"steps":[{"title":"Find studs","description":"Stud finder, mark centers.","skill_level":"beginner","estimated_minutes":15,"tools_needed":["stud finder"],"materials_needed":[]},{"title":"Level the line","description":"Perfectly horizontal at shelf height.","skill_level":"beginner","estimated_minutes":10,"tools_needed":["level"],"materials_needed":[]},{"title":"Screw brackets to studs","description":"Lag bolts ideal, 2 brackets per shelf minimum.","skill_level":"beginner","estimated_minutes":30,"tools_needed":["drill","socket wrench"],"materials_needed":[{"name":"Floating shelf brackets","quantity":3,"unit":"sets"}]}]},{"title":"Hang","description":"Drill back of shelf, slide on.","reason":"The magic moment.","estimated_cost":10,"estimated_hours":2,"steps":[{"title":"Mark rod positions on shelf back","description":"Measure twice.","skill_level":"intermediate","estimated_minutes":20,"tools_needed":["tape measure"],"materials_needed":[]},{"title":"Drill holes for rods","description":"Slightly larger than rod diameter. Drill straight.","skill_level":"intermediate","estimated_minutes":30,"tools_needed":["drill","drill bit"],"materials_needed":[]},{"title":"Slide shelves onto brackets","description":"Tap with rubber mallet if needed.","skill_level":"beginner","estimated_minutes":15,"tools_needed":["rubber mallet"],"materials_needed":[]}]}]}'::jsonb
),
(
  'Concrete Planter (Modern)',
  'Cast a minimalist concrete planter from quick-set mix. Makes a $40 planter for about $8.',
  'decor',
  'https://images.unsplash.com/photo-1485955900006-10f4d324d411?w=800&h=1000&fit=crop',
  true, true, true, 891, 4.9, 'beginner',
  ARRAY['concrete','planter','modern','casting']::text[], 32.00, 3.0,
  '{"stages":[{"title":"Prep Molds","description":"Two nested containers.","reason":"Concrete takes the shape of the mold.","estimated_cost":5,"estimated_hours":1,"steps":[{"title":"Pick outer mold","description":"Any plastic container. Milk cartons work great.","skill_level":"beginner","estimated_minutes":15,"tools_needed":[],"materials_needed":[{"name":"Outer container","quantity":1,"unit":"piece"}]},{"title":"Pick inner mold","description":"Smaller, leaves 1 inch wall.","skill_level":"beginner","estimated_minutes":10,"tools_needed":[],"materials_needed":[{"name":"Inner container","quantity":1,"unit":"piece"}]},{"title":"Spray with cooking oil","description":"Release agent — skip and concrete sticks.","skill_level":"beginner","estimated_minutes":5,"tools_needed":[],"materials_needed":[{"name":"Cooking spray","quantity":1,"unit":"can"}]}]},{"title":"Mix & Pour","description":"Quick-set concrete.","reason":"Work fast once mixed.","estimated_cost":20,"estimated_hours":1,"steps":[{"title":"Mix to pancake batter","description":"Add water slowly.","skill_level":"beginner","estimated_minutes":10,"tools_needed":["bucket","stirrer"],"materials_needed":[{"name":"Quick-set concrete","quantity":1,"unit":"bag"}]},{"title":"Pour outer mold halfway","description":"Fill to half depth.","skill_level":"beginner","estimated_minutes":5,"tools_needed":[],"materials_needed":[]},{"title":"Weight inner mold","description":"Center and weight with rocks.","skill_level":"beginner","estimated_minutes":10,"tools_needed":[],"materials_needed":[{"name":"Weight rocks","quantity":1,"unit":"handful"}]},{"title":"Fill sides and smooth","description":"Top off the gap. Tap to release bubbles.","skill_level":"beginner","estimated_minutes":10,"tools_needed":[],"materials_needed":[]}]},{"title":"Unmold","description":"Release and finish.","reason":"The reveal.","estimated_cost":7,"estimated_hours":1,"steps":[{"title":"Remove inner mold","description":"Twist and pull after 24 hours.","skill_level":"beginner","estimated_minutes":10,"tools_needed":[],"materials_needed":[]},{"title":"Flip and release outer","description":"Tap or slice off plastic.","skill_level":"beginner","estimated_minutes":10,"tools_needed":["utility knife"],"materials_needed":[]},{"title":"Sand edges","description":"Smooth rough spots with wet sandpaper.","skill_level":"beginner","estimated_minutes":20,"tools_needed":["sandpaper"],"materials_needed":[]},{"title":"Drill drainage and plant","description":"Masonry bit for drainage hole.","skill_level":"beginner","estimated_minutes":15,"tools_needed":["drill","masonry bit"],"materials_needed":[{"name":"Plant","quantity":1,"unit":"piece"},{"name":"Potting soil","quantity":1,"unit":"bag"}]}]}]}'::jsonb
