(
  'Macrame Wall Hanging',
  'Modern boho wall art in an afternoon. Square knots, half hitches, gathering knots — all beginner-friendly.',
  'decor',
  'https://images.unsplash.com/photo-1531346878377-a5be20888e57?w=800&h=1200&fit=crop',
  true, true, false, 524, 4.7, 'beginner',
  ARRAY['macrame','wall art','boho','fiber']::text[], 22.00, 3.5,
  '{"stages":[{"title":"Cut Cord","description":"Measure, cut, attach to dowel.","reason":"Same length cords save headaches.","estimated_cost":15,"estimated_hours":1,"steps":[{"title":"Gather materials","description":"Cotton cord 3-5mm, dowel, sharp scissors.","skill_level":"beginner","estimated_minutes":15,"tools_needed":["scissors"],"materials_needed":[{"name":"Cotton macrame cord","quantity":1,"unit":"spool"},{"name":"Wooden dowel","quantity":1,"unit":"piece"}]},{"title":"Cut 12 cords at 8 feet","description":"Doubled = 4 foot working length.","skill_level":"beginner","estimated_minutes":15,"tools_needed":["scissors"],"materials_needed":[]},{"title":"Attach with larks head knots","description":"Fold, loop, pull through.","skill_level":"beginner","estimated_minutes":20,"tools_needed":[],"materials_needed":[]}]},{"title":"Knot Pattern","description":"Square knots and half hitches.","reason":"Start simple.","estimated_cost":0,"estimated_hours":2,"steps":[{"title":"Row 1 square knots","description":"Groups of 4 cords.","skill_level":"beginner","estimated_minutes":30,"tools_needed":[],"materials_needed":[]},{"title":"Row 2 offset square knots","description":"Shift groups by 2 cords.","skill_level":"beginner","estimated_minutes":30,"tools_needed":[],"materials_needed":[]},{"title":"Row 3 diagonal half hitches","description":"Creates V shapes.","skill_level":"intermediate","estimated_minutes":30,"tools_needed":[],"materials_needed":[]},{"title":"Gathering knot base","description":"Wrap center bundle tight.","skill_level":"beginner","estimated_minutes":15,"tools_needed":[],"materials_needed":[]}]},{"title":"Trim & Hang","description":"Shape and mount.","reason":"Trim last for the hang.","estimated_cost":7,"estimated_hours":1,"steps":[{"title":"Trim to shape","description":"V or straight or asymmetric.","skill_level":"beginner","estimated_minutes":15,"tools_needed":["scissors"],"materials_needed":[]},{"title":"Comb out ends","description":"Pet brush unravels fibers for boho look.","skill_level":"beginner","estimated_minutes":15,"tools_needed":["comb"],"materials_needed":[]},{"title":"Tie hanging cord","description":"Piece of cord to each dowel end.","skill_level":"beginner","estimated_minutes":5,"tools_needed":[],"materials_needed":[]},{"title":"Hang","description":"Small nail or hook.","skill_level":"beginner","estimated_minutes":5,"tools_needed":["hammer"],"materials_needed":[{"name":"Picture hook","quantity":1,"unit":"piece"}]}]}]}'::jsonb
