  '{"stages":[{"title":"Shape","description":"Roll and form the dish.","reason":"Cannot reshape once dry.","estimated_cost":8,"estimated_hours":1,"steps":[{"title":"Knead clay ball","description":"2 min until smooth and pliable.","skill_level":"beginner","estimated_minutes":10,"tools_needed":[],"materials_needed":[{"name":"Air-dry clay","quantity":1,"unit":"package"}]},{"title":"Roll flat","description":"1/2 inch thick with rolling pin.","skill_level":"beginner","estimated_minutes":10,"tools_needed":["rolling pin"],"materials_needed":[]},{"title":"Drape over bowl","description":"Flip a small bowl and drape to shape.","skill_level":"beginner","estimated_minutes":15,"tools_needed":["small bowl"],"materials_needed":[]},{"title":"Texture edges","description":"Stamps, leaves, or a fork.","skill_level":"beginner","estimated_minutes":10,"tools_needed":[],"materials_needed":[]}]},{"title":"Dry","description":"Air dry completely.","reason":"Painting wet clay ruins it.","estimated_cost":0,"estimated_hours":0.1,"steps":[{"title":"Dry 24-48 hours","description":"Flip halfway so both sides dry evenly.","skill_level":"beginner","estimated_minutes":5,"tools_needed":[],"materials_needed":[]},{"title":"Sand rough edges","description":"Fine sandpaper on rim.","skill_level":"beginner","estimated_minutes":10,"tools_needed":["sandpaper"],"materials_needed":[]}]},{"title":"Paint & Seal","description":"Acrylic and gloss varnish.","reason":"Sealing makes it feel ceramic.","estimated_cost":7,"estimated_hours":1.5,"steps":[{"title":"Prime white","description":"White base makes colors pop.","skill_level":"beginner","estimated_minutes":20,"tools_needed":["paintbrush"],"materials_needed":[{"name":"White acrylic","quantity":1,"unit":"bottle"}]},{"title":"Paint design","description":"Acrylic is forgiving.","skill_level":"beginner","estimated_minutes":45,"tools_needed":["paintbrush"],"materials_needed":[{"name":"Acrylic paints","quantity":1,"unit":"set"}]},{"title":"Seal with varnish","description":"Two thin coats. 24 hour cure.","skill_level":"beginner","estimated_minutes":20,"tools_needed":["brush"],"materials_needed":[{"name":"Gloss varnish","quantity":1,"unit":"bottle"}]}]}]}'::jsonb
