(
  'Resin River Coasters',
  'Wood and epoxy coasters with a colored river running through. High-end gift look, $10 per set to make.',
  'craft',
  'https://images.unsplash.com/photo-1530018607912-eff2daa1bac4?w=800&h=800&fit=crop',
  true, true, false, 298, 4.5, 'intermediate',
  ARRAY['resin','epoxy','coasters','wood','gift']::text[], 45.00, 8.0,
  '{"stages":[{"title":"Prep","description":"Cut wood and prep molds.","reason":"Dry work before wet keeps shop clean.","estimated_cost":15,"estimated_hours":1.5,"steps":[{"title":"Cut wood strips","description":"Fit the mold with gap for the river.","skill_level":"intermediate","estimated_minutes":45,"tools_needed":["miter saw"],"materials_needed":[{"name":"Wood scraps","quantity":1,"unit":"bundle"}]},{"title":"Sand to 220","description":"Any roughness shows in resin.","skill_level":"beginner","estimated_minutes":20,"tools_needed":["sandpaper"],"materials_needed":[]},{"title":"Prep mold","description":"Light spray of release.","skill_level":"beginner","estimated_minutes":5,"tools_needed":[],"materials_needed":[{"name":"Silicone mold","quantity":1,"unit":"set"}]},{"title":"Arrange wood in mold","description":"Leave 1/2 inch gap for river.","skill_level":"beginner","estimated_minutes":15,"tools_needed":[],"materials_needed":[]}]},{"title":"Mix Resin","description":"Two-part epoxy plus pigment.","reason":"Work in ventilation with gloves.","estimated_cost":20,"estimated_hours":1,"steps":[{"title":"Measure 1:1","description":"Digital scale for accuracy.","skill_level":"intermediate","estimated_minutes":10,"tools_needed":["scale","cups"],"materials_needed":[{"name":"Epoxy resin kit","quantity":1,"unit":"kit"}]},{"title":"Stir 3 minutes","description":"Slow. Scrape sides.","skill_level":"intermediate","estimated_minutes":5,"tools_needed":["stir stick"],"materials_needed":[]},{"title":"Add pigment","description":"Start tiny, a drop at a time.","skill_level":"intermediate","estimated_minutes":5,"tools_needed":[],"materials_needed":[{"name":"Resin pigment","quantity":1,"unit":"bottle"}]}]},{"title":"Pour & Cure","description":"Pour river, wait.","reason":"Cure fully before demolding.","estimated_cost":0,"estimated_hours":0.2,"steps":[{"title":"Pour slowly","description":"Drizzle into gap. Wood bleeds a bit.","skill_level":"intermediate","estimated_minutes":15,"tools_needed":[],"materials_needed":[]},{"title":"Pop bubbles","description":"Quick pass with heat gun or lighter.","skill_level":"intermediate","estimated_minutes":5,"tools_needed":["heat gun"],"materials_needed":[]},{"title":"Cure 24-48 hours","description":"Cover to keep dust off.","skill_level":"beginner","estimated_minutes":5,"tools_needed":[],"materials_needed":[]}]},{"title":"Finish","description":"Demold and polish.","reason":"The reward.","estimated_cost":10,"estimated_hours":2,"steps":[{"title":"Flex and release","description":"Silicone pops out easy.","skill_level":"beginner","estimated_minutes":10,"tools_needed":[],"materials_needed":[]},{"title":"Wet sand 400 to 2000","description":"Glass-smooth finish.","skill_level":"intermediate","estimated_minutes":60,"tools_needed":["wet sandpaper"],"materials_needed":[]},{"title":"Buff with polish","description":"Mirror shine.","skill_level":"intermediate","estimated_minutes":30,"tools_needed":["cloth"],"materials_needed":[{"name":"Plastic polish","quantity":1,"unit":"bottle"}]},{"title":"Add cork backing","description":"Protects furniture.","skill_level":"beginner","estimated_minutes":15,"tools_needed":["scissors"],"materials_needed":[{"name":"Cork sheet","quantity":1,"unit":"sheet"}]}]}]}'::jsonb
