(
  'Raised Garden Bed 4x8',
  'Classic cedar raised bed in one afternoon. No digging, 6 boards and screws.',
  'outdoor',
  'https://images.unsplash.com/photo-1585320806297-9794b3e4eeae?w=800&h=600&fit=crop',
  true, true, false, 678, 4.8, 'beginner',
